-- 已核验数据导入脚本（第四批）
-- 核验时间：2026-04-20
-- 说明：
-- 1. 仅导入从学校官方历年分数查询接口直接返回的黑龙江 2025 明细。
-- 2. 黑龙江大学接口需先请求 csrfToken，再按前端真实请求头回放 ajax_lnfs_param/ajax_lnfs。
-- 3. 东北农业大学接口来自本科招生信息网历年分数页。

ON CONFLICT (name, province) DO UPDATE SET
    city = EXCLUDED.city,
    level = EXCLUDED.level,
    is_985 = EXCLUDED.is_985,
    is_211 = EXCLUDED.is_211,
    is_double_first = EXCLUDED.is_double_first,
    source_name = EXCLUDED.source_name,
    source_url = EXCLUDED.source_url,
    updated_at = CURRENT_TIMESTAMP;

ON CONFLICT (college_id, province, year, subject, batch, admission_type) DO UPDATE SET
    min_score = EXCLUDED.min_score,
    min_rank = EXCLUDED.min_rank,
    avg_score = EXCLUDED.avg_score,
    max_score = EXCLUDED.max_score,
    source_name = EXCLUDED.source_name,
    source_url = EXCLUDED.source_url,
    updated_at = CURRENT_TIMESTAMP;

UPDATE college_score_line SET subject = regexp_replace(subject, '\s+', '', 'g'), batch = regexp_replace(batch, '\s+', '', 'g'), admission_type = regexp_replace(admission_type, '\s+', '', 'g') WHERE source_url IN ('https://zsbcx.hlju.edu.cn/static/front/hlju/basic/html_web/lnfs.html', 'https://zsb.neau.edu.cn/static/front/neau/basic/html_web/lnfs.html');
